// // When a = 3, q should be 8a0b; when a = 5, q should be 2def; when a = 0, q should be 9f18; when a = 1, q should be 3d52; when a = 2, q should be b0b6; when a = 4, q should be 58a9; when a = 7, q should be 306b; when a = 6, q should be 3f3a.
module top_module (
    input [2:0] a,
    output reg [15:0] q
);  always @(*)
    case (a)
      0: q = 16'h9f18;
      1: q = 16'h3d52;
      2: q = 16'hb0b6;
      3: q = 16'h8a0b;
      4: q = 16'h58a9;
      5: q = 16'h2def;
      6: q = 16'h3f3a;
      7: q = 16'h306b;
    endcase

endmodule
